  "inlineSchema": "// Prisma schema for \"Na Sua Porta\" MVP\n// Delivery platform for condominiums\n\ngenerator client {\n  provider        = \"prisma-client\"\n  output          = \"../src/generated\"\n  previewFeatures = []\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// Condominium model (multi-tenant support)\nmodel Condominium {\n  id      String  @id @default(cuid())\n  name    String\n  address String?\n  active  Boolean @default(true)\n\n  // Service configuration\n  operatingHours      String? // e.g. \"08:00–22:00\"\n  maxActiveDeliveries Int? // max simultaneous active deliveries\n\n  users      User[]\n  deliveries Delivery[]\n  vendors    Vendor[]\n  orders     Order[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// User model (handles both residents and delivery persons)\nmodel User {\n  id        String   @id @default(cuid())\n  email     String   @unique\n  password  String\n  name      String\n  phone     String?\n  role      UserRole @default(RESIDENT)\n  apartment String? // Only for RESIDENT role (format: \"101\", \"201\", etc)\n  block     String? // Only for RESIDENT role (format: \"A\", \"B\", etc)\n  active    Boolean  @default(true)\n\n  vehicleInfo      String? // Only for DELIVERY_PERSON (e.g. \"Moto - ABC-1234\")\n  personalDocument String? // Required for DELIVERY_PERSON (RG/CPF)\n\n  // Multi-condominium\n  condominiumId String?\n  condominium   Condominium? @relation(fields: [condominiumId], references: [id])\n\n  // Relations\n  createdDeliveries  Delivery[]     @relation(\"CreatedBy\")\n  acceptedDeliveries Delivery[]     @relation(\"AcceptedBy\")\n  createdOrders      Order[]        @relation(\"OrderCreatedBy\")\n  orderMessages      OrderMessage[]\n  vendorProfile      Vendor?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([condominiumId])\n}\n\nenum UserRole {\n  RESIDENT\n  DELIVERY_PERSON\n  VENDOR\n  CONDOMINIUM_ADMIN\n}\n\n// Delivery model\nmodel Delivery {\n  id     String         @id @default(cuid())\n  status DeliveryStatus @default(REQUESTED)\n  type   DeliveryType   @default(PORTARIA)\n\n  // Resident info\n  residentId String\n  resident   User   @relation(\"CreatedBy\", fields: [residentId], references: [id])\n  apartment  String\n  block      String\n\n  // Delivery person info\n  deliveryPersonId String?\n  deliveryPerson   User?   @relation(\"AcceptedBy\", fields: [deliveryPersonId], references: [id])\n\n  // Multi-condominium\n  condominiumId String?\n  condominium   Condominium? @relation(fields: [condominiumId], references: [id])\n\n  // Marketplace relation\n  orderId String? @unique\n  order   Order?  @relation(fields: [orderId], references: [id])\n\n  // Delivery details\n  pickupOrigin            String? // e.g. \"Portaria\" or vendor name for marketplace\n  description             String?\n  notes                   String?\n  externalPlatform        String? // Platform the resident ordered from (e.g. \"iFood\", \"Amazon\")\n  externalCode            String? // Receiving code informed by the resident\n  deliveryCode            String? // Code generated on acceptance, required to mark as DELIVERED\n  deliveryCodeGeneratedAt DateTime?\n  rating                  Int? // 1-5 stars, set by resident after delivery\n  ratingComment           String? // Optional comment on rating\n\n  // Timestamps\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  acceptedAt  DateTime?\n  pickedUpAt  DateTime?\n  deliveredAt DateTime?\n\n  @@index([residentId])\n  @@index([deliveryPersonId])\n  @@index([status])\n  @@index([condominiumId])\n  @@index([type])\n}\n\nmodel Vendor {\n  id                          String     @id @default(cuid())\n  name                        String\n  description                 String?\n  category                    String? // e.g. \"Restaurante\", \"Mercado\", \"Farmácia\"\n  imageUrl                    String?\n  bannerUrl                   String?\n  aboutText                   String?\n  contactPhone                String?\n  cnpj                        String?\n  cnae                        String?\n  legalRepresentativeDocument String?\n  estimatedTimeMinutes        Int?       @default(30)\n  minOrderValue               Float?     @default(0)\n  rating                      Float?     @default(4.5)\n  type                        VendorType @default(RESIDENT)\n  active                      Boolean    @default(true)\n\n  condominiumId String?\n  condominium   Condominium? @relation(fields: [condominiumId], references: [id])\n\n  userId String? @unique\n  user   User?   @relation(fields: [userId], references: [id])\n\n  menuItems MenuItem[]\n  orders    Order[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([condominiumId])\n  @@index([type])\n}\n\nmodel MenuItem {\n  id          String  @id @default(cuid())\n  name        String\n  description String?\n  price       Float\n  category    String?\n  available   Boolean @default(true)\n  imageUrl    String?\n\n  vendorId String\n  vendor   Vendor @relation(fields: [vendorId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([vendorId])\n}\n\nmodel Order {\n  id            String        @id @default(cuid())\n  status        OrderStatus   @default(PENDING)\n  paymentStatus PaymentStatus @default(PENDING)\n\n  customerName String\n  apartment    String\n  block        String?\n  description  String\n  totalAmount  Float   @default(0)\n  source       String? // e.g. \"app\", \"whatsapp\"\n\n  vendorId String?\n  vendor   Vendor? @relation(fields: [vendorId], references: [id])\n\n  condominiumId String?\n  condominium   Condominium? @relation(fields: [condominiumId], references: [id])\n\n  createdByUserId String?\n  createdByUser   User?   @relation(\"OrderCreatedBy\", fields: [createdByUserId], references: [id])\n\n  delivery Delivery?\n  messages OrderMessage[]\n\n  acceptedAt            DateTime?\n  readyAt               DateTime?\n  sentAt                DateTime?\n  completedAt           DateTime?\n  cancelledAt           DateTime?\n  cancelReason          String?\n  cancelledByRole       UserRole?\n  pickupCode            String?\n  pickupCodeGeneratedAt DateTime?\n  chatEnabledAt         DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([status])\n  @@index([paymentStatus])\n  @@index([condominiumId])\n}\n\nenum DeliveryStatus {\n  REQUESTED // Initial state\n  ACCEPTED // Delivery person accepted\n  PICKED_UP // Item picked up from portaria\n  DELIVERED // Delivered to apartment\n}\n\nenum DeliveryType {\n  PORTARIA\n  MARKETPLACE\n}\n\nenum VendorType {\n  RESIDENT\n  EXTERNAL\n}\n\nenum OrderStatus {\n  PENDING\n  ACCEPTED\n  READY\n  SENT\n  COMPLETED\n  CANCELLED\n}\n\nenum PaymentStatus {\n  PENDING\n  PAID\n}\n\nmodel OrderMessage {\n  id        String   @id @default(cuid())\n  orderId   String\n  order     Order    @relation(fields: [orderId], references: [id])\n  senderId  String\n  sender    User     @relation(fields: [senderId], references: [id])\n  content   String\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  @@index([orderId])\n  @@index([senderId])\n  @@index([expiresAt])\n}\n\n// Event log for tracking delivery lifecycle\nmodel DeliveryEvent {\n  id         String   @id @default(cuid())\n  deliveryId String\n  event      String // e.g. \"CREATED\", \"ACCEPTED\", \"PICKED_UP\", \"DELIVERED\"\n  userId     String? // Who triggered the event\n  metadata   String? // JSON string for additional data\n  createdAt  DateTime @default(now())\n\n  @@index([deliveryId])\n  @@index([event])\n  @@index([createdAt])\n}\n",
